final:
module top_module(I, O, S0, S1);input [3:0] I;
  output O;
  input S0, S1;

  reg [3:0] obf_temp;
  always @ (S0, S1, I) begin
    case ({S1, S0})
      2'b00: obf_temp = I[0];
      2'b01: obf_temp = I[1];
      2'b10: obf_temp = I[2];
      2'b11: obf_temp = I[3];
    endcase
  end

  assign O = obf_temp;
endmodule
